object Solution {
  def nums(nums: Array[Long]): Long = {
    // The problem asks for the maximum number of fixed points we can achieve
    // after deleting any number of elements, where remaining elements shift left.
    //
    // Let the original array be `nums` of length N.
    // Suppose we keep a subsequence of indices $i_0, i_1, \ldots, i_{k-1}$ from $\{0, 1, \ldots, N-1\}$
    // such that $0 \le i_0 < i_1 < \ldots < i_{k-1} < N$.
    //
    // In the new array (of length k), the element originally at index $i_j$ is now at index $j$.
    // We want to maximize k such that for all $j \in \{0, 1, \ldots, k-1\}$, the condition holds:
    // New index $j$ must equal the value at that position: nums[i_j] == j.
    //
    // This is equivalent to finding the longest subsequence $i_0, i_1, \ldots, i_{k-1}$ such that:
    // 1. $i_0 < i_1 < \ldots < i_{k-1}$
    // 2. $nums[i_j] = j$ for all $j=0, 1, \ldots, k-1$.
    //
    // This is a variation of the Longest Increasing Subsequence (LIS) problem, but simplified
    // because the required value $j$ depends only on the length of the prefix, not the value of the previous element.
    // We can use a greedy approach or dynamic programming. Since the required value $j$ is strictly increasing (0, 1, 2, ...),
    // we just need to find the longest sequence of indices $i_j$ such that $nums[i_j] = j$ and $i_j$ are increasing.
    //
    // We iterate through the original array `nums` and keep track of the next target value we are looking for, starting at 0.
    //
    var currentTargetValue = 0
    var fixedPointsCount = 0

    for (i <- 0 until nums.length) {
      // Check if the element at index i matches the next required fixed point value.
      // The required fixed point value is `currentTargetValue`.
      if (nums(i) == currentTargetValue.toLong) {
        // If it matches, we "keep" this element, achieving a fixed point at the new position `currentTargetValue`.
        fixedPointsCount += 1
        // We now look for the next fixed point, which must have value `currentTargetValue + 1`.
        currentTargetValue += 1
      }
      // If it does not match, we "delete" this element (i.e., we skip it) because keeping it would not contribute
      // to the current longest sequence of fixed points based on the greedy choice.
    }

    fixedPointsCount.toLong
  }
}
