class Solution {
  /**
    * @param nums The input integer array.
    * @return The maximum number of fixed points achievable after deletions.
    */
  def nums(nums: Array[Long]): Long = {
    val n = nums.length
    // We want to select a subsequence of nums, say nums[i_1], nums[i_2], ..., nums[i_k]
    // such that if this subsequence becomes the new array (after shifting),
    // the maximum number of fixed points is achieved.
    // In the new array, the element at index j (which was originally at index i_j)
    // must satisfy nums[i_j] == j.

    // Let's rephrase: we are looking for the longest subsequence such that
    // for the j-th element in the subsequence (0-indexed), its value is j.
    // If the chosen subsequence is S = [s_0, s_1, ..., s_{k-1}], we want s_j = j for maximum j.
    // This means we are looking for the longest subsequence where the j-th element is equal to j.

    // We can use a greedy approach. We iterate through the original array nums.
    // We maintain a counter 'expected_value', which represents the index (and thus the required value)
    // of the next element we want to include in our subsequence to form a fixed point.

    var fixedPointsCount: Long = 0
    var expectedValue: Long = 0 // This represents the index of the next potential fixed point (0, 1, 2, ...)

    for (i <- 0 until n) {
      val currentValue = nums(i)

      // If the current value matches the value required for the next fixed point (expectedValue),
      // we "keep" this element in our subsequence, increment the fixed point count,
      // and update the expected value for the next potential fixed point.
      if (currentValue == expectedValue) {
        fixedPointsCount += 1
        expectedValue += 1
      }
    }

    fixedPointsCount
  }
}
