def solve(nums: Array[Long]): Long = {
  // The problem asks for the maximum number of fixed points after deleting any subset of elements.
  // A fixed point at index j means the element at that index is equal to j.
  // If we keep a subsequence of the original array nums, let the indices kept be i_0, i_1, ..., i_{k-1}
  // where 0 <= i_0 < i_1 < ... < i_{k-1} < nums.length.
  // The new array will be [nums[i_0], nums[i_1], ..., nums[i_{k-1}]].
  // A fixed point occurs at new index j if nums[i_j] == j.
  // We want to maximize k such that there exists a subsequence satisfying this condition.
  // This is equivalent to finding the Longest Increasing Subsequence (LIS) with a specific constraint,
  // or more simply, a greedy approach based on the required value.

  // Let's rephrase: We are looking for the longest subsequence nums[i_0], nums[i_1], ..., nums[i_{k-1}]
  // such that for all j from 0 to k-1, nums[i_j] == j.

  // We iterate through the original array and greedily select elements that match the next required index.

  var count = 0 // This will be the index of the next required fixed point (0, 1, 2, ...)

  for (i <- nums.indices) {
    val currentElement = nums(i)

    // If the current element matches the next required fixed point index, we select it.
    // If we select it, it contributes to the count, and we look for the next required fixed point (count + 1).
    if (currentElement == count.toLong) {
      count += 1
    }
  }

  count.toLong
}
